CREATE TABLE IF NOT EXISTS shipevent (internal_id BIGINT PRIMARY KEY, project INT NOT NULL, ship_number INT NOT NULL, created_at TIMESTAMP NOT NULL, demo_url VARCHAR(2048) NOT NULL, repo_url VARCHAR(2048) NOT NULL, devlog_count INT NOT NULL, ship_count INT NOT NULL, description VARCHAR(4000) NOT NULL, first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NULL, last_seen_iteration INT NULL, CONSTRAINT fk_shipevent_project__id FOREIGN KEY (project) REFERENCES projects(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_shipevent_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);